const { APP_DEFAULT_BASE_PATH } = require('./constants/files-discovery');
const { NordicPagesDiscovery } = require('./discovery/nordic-pages-discovery');
const { astCache } = require('./cache/ast-cache');
const { importsCache } = require('./cache/imports-cache');
const {
  writeDiscoveryManifest,
  readDiscoveryManifest,
} = require('./helpers/file-system/discovery-manifest');
const {
  writeIslandsManifest,
} = require('./helpers/file-system/islands-manifest');
const {
  getAllIslands,
  getIslandByFullPath,
} = require('./islands/get-from-manifest');

/**
 * @typedef { keyof typeof import('./constants/device').DEVICE_TYPES } DeviceType
 * @typedef { import('./page/paths').Paths } Paths
 * @typedef { { [device in DeviceType]?: Paths } } PagePathsByDevice
 * @typedef { import('./page/navigable-page').NavigablePage } NavigablePage
 *
 * @typedef { object } DiscoveredNordicPages
 * @property { string | undefined } baseHooksFile
 * @property { NavigablePage[] } discoveredNavigablePages
 * @property { { [statusError: string]: { paths: PagePathsByDevice } } } discoveredHttpErrorPages
 */

/**
 * Discovers Nordic Pages and write the discovery manifest
 * @param { string } basePath - Directory path where to find the pages
 */
const discoverNordicPages = (basePath = APP_DEFAULT_BASE_PATH) => {
  astCache.clear();
  importsCache.clear();

  const discovery = new NordicPagesDiscovery(basePath);

  writeIslandsManifest(discovery.clientIslands);
  writeDiscoveryManifest(discovery.getDiscoveredNordicPages());
};

const getDiscoveredNordicPages = () => {
  const result = readDiscoveryManifest();

  return Object.keys(result).length ? result : undefined;
};

module.exports = {
  discoverNordicPages,
  getDiscoveredNordicPages,
  getAllIslands,
  getIslandByFullPath,
};
